from flask_cors import CORS

# ── HTML (내장) ────────────────────────────────────────────
_HTML_B64 = ""

def get_html() -> str:
    return base64.b64decode(_HTML_B64).decode("utf-8")

# ── Flask 앱 ──────────────────────────────────────────────
app  = Flask(__name__)
CORS(app)

KIS_REAL = "https://openapi.koreainvestment.com:9443"
KIS_DEMO = "https://openapivts.koreainvestment.com:9443"

# ── 토큰 캐시 (메모리 + 파일 이중 저장) ──────────────────
# EXE 재실행 시에도 토큰 유지 (24시간)
_token_cache = {}

def _cache_path() -> Path:
    """토큰 캐시 파일 경로 — EXE 위치와 동일한 폴더"""
    if getattr(sys, 'frozen', False):
        base = Path(sys.executable).parent
    else:
        base = Path(__file__).parent
    return base / ".kis_token_cache.json"

def _load_cache():
    """파일에서 캐시 로드"""
    try:
        p = _cache_path()
        if p.exists():
            data = json.loads(p.read_text(encoding='utf-8'))
            now  = time.time()
            # 만료된 항목 제거
            return {k: v for k, v in data.items()
                    if v.get("expires_at", 0) - now > 300}
    except Exception:
        pass
    return {}

def _save_cache(cache: dict):
    """캐시를 파일에 저장"""
    try:
        # tuple key → string으로 변환
        serializable = {str(k): v for k, v in cache.items()}
        _cache_path().write_text(
            json.dumps(serializable, ensure_ascii=False, indent=2),
            encoding='utf-8'
        )
    except Exception:
        pass

# 시작 시 파일 캐시 복원
_token_cache = _load_cache()
print(f"[토큰캐시] {len(_token_cache)}개 복원됨")

def base_url(env): return KIS_REAL if env == "prod" else KIS_DEMO

# ── 메인 페이지 ───────────────────────────────────────────
@app.route("/")
def index():
    return Response(get_html(), mimetype="text/html; charset=utf-8")

