@app.route("/api/broker")
def broker():
    env=request.args.get("env","prod"); token=request.args.get("token","")
    appkey=request.args.get("appkey",""); appsecret=request.args.get("appsecret","")
    market=request.args.get("market","J"); code=request.args.get("code","")
    if not token or not code: return jsonify({"error":"token,code 필수"}),400
    hdrs={"Content-Type":"application/json","authorization":f"Bearer {token}",
          "appkey":appkey,"appsecret":appsecret,"tr_id":"FHKST01010300","custtype":"P"}
    try:
        r=requests.get(base_url(env)+"/uapi/domestic-stock/v1/quotations/inquire-member",
            headers=hdrs,params={"FID_COND_MRKT_DIV_CODE":market,"FID_INPUT_ISCD":code},timeout=10)
        d=r.json()
        if d.get("rt_cd")!="0": return jsonify({"error":d.get("msg1","API 오류")}),400
        out=d.get("output",{})
        sell=[{"name":out.get(f"seln_mbcr_name{i}","").strip(),"vol":int(out.get(f"seln_mbcr_qty{i}",0) or 0)} for i in range(1,6) if out.get(f"seln_mbcr_name{i}","").strip()]
        buy =[{"name":out.get(f"shnu_mbcr_name{i}","").strip(),"vol":int(out.get(f"shnu_mbcr_qty{i}",0) or 0)} for i in range(1,6) if out.get(f"shnu_mbcr_name{i}","").strip()]
        return jsonify({"sell":sell,"buy":buy})
    except Exception as e: return jsonify({"error":str(e)}),502


