PORT = 5000

def open_browser():
    time.sleep(1.5)
    webbrowser.open(f"http://localhost:{PORT}")

def is_port_in_use(port: int) -> bool:
    """포트가 이미 사용 중인지 확인"""
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
        s.settimeout(0.5)
        return s.connect_ex(('127.0.0.1', port)) == 0

if __name__ == "__main__":
    if sys.platform == "win32":
        os.system("title KIS 스마트머니 레이더")

    print()
    print("=" * 58)
    print("  📡  KIS 스마트머니 레이더  v2.0")
    print("=" * 58)

    # ── 포트 충돌 감지: 이미 실행 중이면 브라우저만 열기 ──
    if is_port_in_use(PORT):
        print(f"  ℹ️  이미 실행 중인 서버 감지 (localhost:{PORT})")
        print(f"  🌐  기존 창으로 이동합니다...")
        print("=" * 58)
        webbrowser.open(f"http://localhost:{PORT}")
        print()
        print("  브라우저가 열렸습니다. 이 창은 닫아도 됩니다.")
        time.sleep(3)
        sys.exit(0)

    print(f"  ✅  서버 시작: http://localhost:{PORT}")
    print(f"  🌐  브라우저가 자동으로 열립니다...")
    print(f"  ⛔  종료하려면 이 창을 닫으세요")
    print("=" * 58)
    print()

    # 브라우저 자동 오픈
    threading.Thread(target=open_browser, daemon=True).start()

    # Flask 서버 실행
    app.run(host="127.0.0.1", port=PORT, debug=False, use_reloader=False)
